args.sparql:
SELECT ?title WHERE { 
  ?book wdt:P179 wd:Q4470 ;
        wdt:P1545 "1" ;
        rdfs:label ?title .
  FILTER(LANG(?title) = "en")
}

SELECT ?title WHERE {
  wd:Q4470 wdt:P1433 ?book .
  ?book wdt:P1545 "1" .
  ?book wdt:P1476 ?title .
  FILTER(LANG(?title) = "en")
}

SELECT ?title WHERE { 
  ?book wdt:P179 wd:Q4470 ; 
        wdt:P577 ?date ; 
        wdt:P1476 ?title . 
  FILTER (LANG(?title) = "en") 
} ORDER BY ASC(?date) LIMIT 1
